<?php function current_student($conn){$uid=(int)($_SESSION['user_id']??0);$s=$conn->prepare('SELECT u.email,u.student_id,s.* FROM users u LEFT JOIN students s ON s.id=u.student_id WHERE u.id=?');$s->execute([$uid]);$r=$s->fetch();if($r&&!empty($r['id']))return $r;if($r&&!empty($r['email'])){$q=$conn->prepare('SELECT * FROM students WHERE email=?');$q->execute([$r['email']]);return $q->fetch();}return null;}function require_student_record($conn){$s=current_student($conn);if(!$s){student_header('Student Portal');echo '<section class="panel">No student record linked.</section>';page_footer();exit;}return $s;}?>